import{_ as o,o as r,c as a,a3 as e}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"网页蒸馏室","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/web-distillery.md","filePath":"user-guide/tools/web-distillery.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/web-distillery.md"};function d(i,t,n,s,c,h){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="网页蒸馏室" tabindex="-1">网页蒸馏室 <a class="header-anchor" href="#网页蒸馏室" aria-label="Permalink to &quot;网页蒸馏室&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>网页蒸馏室是一个高纯度的网页内容提取工具。它支持从<strong>快速 HTTP 获取</strong>到<strong>交互式浏览器爬取</strong>三种不同粒度的提取模式，能将网页中的噪音（广告、导航栏、侧边栏）滤除，只保留你真正需要的内容。</p><div class="tip custom-block"><p class="custom-block-title">核心场景</p><p>你想把一篇博客文章保存为 Markdown？需要从某个动态页面提取数据但页面用了大量 JS 渲染？或者想为某个网站定制一套自动提取规则以后反复使用？网页蒸馏室就是帮你做这些事的。</p></div><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>三层蒸馏模式</strong>：快速模式（纯 HTTP 请求，毫秒级）、智能模式（隐藏浏览器渲染，支持 SPA）、交互模式（可视化配方编辑），按需选择</li><li><strong>智能内容清洗</strong>：6 阶段蒸馏管道自动完成去噪、提取、格式转换，结果像直接蒸馏过一样纯净</li><li><strong>站点配方系统</strong>：内置 Bilibili、微信公众号、GitHub、GitLab 等高频站点的提取规则，支持用户自定义持久化配方</li><li><strong>身份与 API 嗅探</strong>：管理 Cookie 身份信息，自动发现页面的 API 请求，方便逆向分析</li><li><strong>Agent 自动化能力</strong>：可直接被 AI 助手调用，支持 <code>quickFetch</code>（静态页）和 <code>smartExtract</code>（动态页）两种 Agent 接口</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次提取页面-5-步走" tabindex="-1">首次提取页面 5 步走 <a class="header-anchor" href="#首次提取页面-5-步走" aria-label="Permalink to &quot;首次提取页面 5 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>网页蒸馏室</strong>，点击进入。默认进入 <strong>蒸馏工作台</strong> 标签页。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注默认的工作台、输入框和三个模式按钮</p></blockquote><p><strong>第二步：输入 URL</strong></p><p>在顶部地址栏输入目标网页的完整 URL（例如 <code>https://example.com/article</code>），然后选择提取模式：</p><ul><li><strong>快速模式</strong>：⚡ 最快的选择，纯 HTTP 请求获取内容。适合静态博客、文档页面</li><li><strong>智能模式</strong>：🧠 启动隐藏浏览器渲染页面，支持 JS 动态加载。适合 SPA、需要登录的页面</li></ul><blockquote><p>TODO: 截图 - 地址栏输入 URL 后，标注快速/智能模式按钮</p></blockquote><p><strong>第三步：开始蒸馏</strong></p><p>点击 <strong>获取内容</strong> 按钮（或按回车），工具开始抓取并清洗网页。</p><p>对于快速模式，结果通常在几秒内返回。智能模式因为要启动隐藏浏览器，会稍慢一些。</p><blockquote><p>TODO: 截图 - 加载过程中的进度提示</p></blockquote><p><strong>第四步：查看结果</strong></p><p>提取完成后，左侧预览区显示清洗后的内容，右侧信息栏展示提取质量评分、字数统计、匹配配方等元数据。</p><blockquote><p>TODO: 截图 - 结果展示页面，标注预览区和右侧信息面板</p></blockquote><p><strong>第五步：使用结果</strong></p><p>结果区的操作栏提供以下功能：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>发送到聊天</td><td>将提取内容直接发送到 AI 聊天会话，继续与 AI 对话</td></tr><tr><td>查看原文</td><td>切换到原始 HTML 源码视图，便于排查提取问题</td></tr><tr><td>查看元数据</td><td>切换展示提取到的页面元数据（标题、作者、发布日期等）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 结果区操作栏，标注&quot;发送到聊天&quot;等按钮</p></blockquote><h3 id="拖放本地文件" tabindex="-1">拖放本地文件 <a class="header-anchor" href="#拖放本地文件" aria-label="Permalink to &quot;拖放本地文件&quot;">​</a></h3><p>你还可以直接拖放本地的 <code>.html</code> 或 <code>.htm</code> 文件到工作台进行蒸馏处理——这对于调试本地页面或处理离线保存的网页非常有用。</p><blockquote><p>TODO: 截图 - 拖放文件到工作台的动画示意</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="工作台-蒸馏工作台" tabindex="-1">工作台（蒸馏工作台） <a class="header-anchor" href="#工作台-蒸馏工作台" aria-label="Permalink to &quot;工作台（蒸馏工作台）&quot;">​</a></h3><p>工作台是核心操作界面，采用&quot;左预览 + 右侧信息&quot;的布局。</p><h4 id="地址栏与工具栏" tabindex="-1">地址栏与工具栏 <a class="header-anchor" href="#地址栏与工具栏" aria-label="Permalink to &quot;地址栏与工具栏&quot;">​</a></h4><p>顶部工具栏集成了完整的操作入口：</p><ul><li><strong>URL 输入框</strong>：输入目标网页地址</li><li><strong>加载状态指示器</strong>：显示当前加载进度</li><li><strong>模式切换</strong>：快速 / 智能两种提取模式</li><li><strong>刷新按钮</strong>：使用相同模式重新提取当前 URL</li><li><strong>打开交互配方</strong>：快速跳转到交互模式，对当前页面进行精细化配方编辑</li></ul><blockquote><p>TODO: 截图 - 顶部工具栏，标注各功能区域</p></blockquote><h4 id="结果预览区" tabindex="-1">结果预览区 <a class="header-anchor" href="#结果预览区" aria-label="Permalink to &quot;结果预览区&quot;">​</a></h4><p>展示蒸馏后的网页内容。支持两种视图切换：</p><ul><li><strong>提取结果</strong>：默认视图，展示清洗后的纯净内容</li><li><strong>原始快照</strong>：切换展示原始 HTML 源码，便于诊断提取效果</li></ul><h4 id="信息侧栏" tabindex="-1">信息侧栏 <a class="header-anchor" href="#信息侧栏" aria-label="Permalink to &quot;信息侧栏&quot;">​</a></h4><p>右侧信息面板展示了提取结果的元数据：</p><table tabindex="0"><thead><tr><th>信息项</th><th>说明</th></tr></thead><tbody><tr><td>提取质量</td><td>0-100% 的质量评分，基于内容完整度和噪音比例</td></tr><tr><td>提取模式</td><td>当前使用的蒸馏模式（fast / smart）</td></tr><tr><td>字数</td><td>提取内容的字符数</td></tr><tr><td>格式</td><td>输出格式（Markdown / Text / HTML / JSON）</td></tr><tr><td>匹配配方</td><td>如果有匹配的站点配方，显示配方名称</td></tr><tr><td>提取时间</td><td>内容获取的时间戳</td></tr></tbody></table><h4 id="拖放上传" tabindex="-1">拖放上传 <a class="header-anchor" href="#拖放上传" aria-label="Permalink to &quot;拖放上传&quot;">​</a></h4><p>工作台支持拖放本地 HTML 文件。将文件拖入工作台区域后，工具会自动读取并蒸馏该文件的内容。</p><h3 id="交互配方" tabindex="-1">交互配方 <a class="header-anchor" href="#交互配方" aria-label="Permalink to &quot;交互配方&quot;">​</a></h3><p>交互模式是网页蒸馏室的&quot;精细化工车间&quot;——它通过 Iframe 加载目标页面，让你像使用浏览器的开发者工具一样，直接在页面上点选元素来定制提取规则。</p><h4 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h4><p><strong>第一步：加载页面</strong></p><p>在交互工作台的地址栏输入 URL 并加载，目标页面会渲染在左侧的浏览器视口中。</p><blockquote><p>TODO: 截图 - 交互模式界面，标注浏览器视口和右侧工具面板</p></blockquote><p><strong>第二步：拾取元素</strong></p><p>点击工具栏的 <strong>🎯 拾取</strong> 按钮进入元素拾取模式。此时：</p><ul><li>鼠标悬停在页面元素上时，元素会高亮显示</li><li>底部状态栏显示当前悬停元素的标签名、选择器和文本预览</li><li>点击元素即可将其加入包含（include）或排除（exclude）规则列表</li></ul><blockquote><p>TODO: 截图 - 拾取模式下的高亮效果和状态栏信息</p></blockquote><p><strong>第三步：管理提取规则</strong></p><p>右侧 <strong>提取规则</strong> 面板展示所有已添加的规则：</p><ul><li><strong>包含规则</strong>（绿色）：指定哪些元素需要保留</li><li><strong>排除规则</strong>（红色）：指定哪些元素需要移除</li><li>支持对规则进行删除和重新排序</li></ul><blockquote><p>TODO: 截图 - 提取规则面板，标注包含/排除规则列表</p></blockquote><p><strong>第四步：配置动作序列</strong></p><p>有些页面需要执行一系列操作才能显示完整内容（如展开&quot;查看更多&quot;按钮、滚动加载等）。在 <strong>动作序列</strong> 面板中，你可以编排以下动作：</p><table tabindex="0"><thead><tr><th>动作类型</th><th>说明</th><th>参数</th></tr></thead><tbody><tr><td><code>click</code></td><td>点击指定元素</td><td>CSS 选择器</td></tr><tr><td><code>scroll</code></td><td>滚动页面</td><td>可选：指定元素 / 距离 / 滚动到底部</td></tr><tr><td><code>wait</code></td><td>等待指定时间或元素出现</td><td>毫秒数 / CSS 选择器</td></tr><tr><td><code>wait-idle</code></td><td>等待页面空闲</td><td>超时时间</td></tr><tr><td><code>remove</code></td><td>在提取前移除元素</td><td>CSS 选择器</td></tr><tr><td><code>input</code></td><td>向输入框填入文本</td><td>选择器 + 值</td></tr><tr><td><code>hover</code></td><td>悬停到指定元素</td><td>CSS 选择器</td></tr></tbody></table><blockquote><p>TODO: 截图 - 动作序列面板，展示已配置的动作步骤</p></blockquote><p><strong>第五步：实时预览</strong></p><p>在编辑规则和动作的同时，<strong>实时预览</strong> 面板会立即展示当前提取结果的变化，方便你边调边看。</p><blockquote><p>TODO: 截图 - 实时预览面板，展示提取效果</p></blockquote><p><strong>第六步：保存为配方</strong></p><p>配置完成后，点击 <strong>保存配方</strong> 按钮，填写配方名称、域名信息并保存。之后访问同一域名的页面时，系统会自动匹配并使用该配方进行提取。</p><blockquote><p>TODO: 截图 - 保存配方弹窗，展示名称、域名、路径模式等字段</p></blockquote><h3 id="站点配方" tabindex="-1">站点配方 <a class="header-anchor" href="#站点配方" aria-label="Permalink to &quot;站点配方&quot;">​</a></h3><p>站点配方是持久化的提取规则集合。工具内置了针对高频站点的预置配方，你也可以创建自己的自定义配方。</p><h4 id="内置配方" tabindex="-1">内置配方 <a class="header-anchor" href="#内置配方" aria-label="Permalink to &quot;内置配方&quot;">​</a></h4><p>目前内置的站点配方包括：</p><table tabindex="0"><thead><tr><th>站点</th><th>适用页面</th></tr></thead><tbody><tr><td>Bilibili</td><td>视频详情页（<code>/video/**</code>）</td></tr><tr><td>微信公众号</td><td>文章页（<code>mp.weixin.qq.com/s/**</code>）</td></tr><tr><td>GitHub</td><td>仓库文件页（<code>blob/**</code>）、原始文件（<code>raw.githubusercontent.com</code>）、Gist</td></tr><tr><td>GitLab</td><td>仓库文件页（<code>-/blob/**</code>）</td></tr><tr><td>Gitee</td><td>原始文件（<code>raw/**</code>）、文件页（<code>blob/**</code>）</td></tr><tr><td>Pastebin</td><td>代码片段页</td></tr><tr><td>npm</td><td>包详情页（<code>/package/**</code>）</td></tr><tr><td>PyPI</td><td>包详情页（<code>/project/**</code>）</td></tr></tbody></table><p>内置配方不可删除，但可以禁用。它们会持续在后台自动匹配，只要访问的 URL 符合配方规则即可生效。</p><blockquote><p>TODO: 截图 - 配方管理页面，展示内置配方和用户配方的卡片列表</p></blockquote><h4 id="配方管理" tabindex="-1">配方管理 <a class="header-anchor" href="#配方管理" aria-label="Permalink to &quot;配方管理&quot;">​</a></h4><p>在 <strong>站点配方</strong> 标签页中，你可以：</p><ul><li><strong>浏览</strong>：通过搜索框快速筛选配方（按名称或域名）</li><li><strong>编辑</strong>：点击编辑按钮跳转到交互模式修改配方规则</li><li><strong>启用/禁用</strong>：切换配方的激活状态</li><li><strong>删除</strong>：删除用户自定义配方（内置配方不可删除）</li><li><strong>查看</strong>：点击域名快速在浏览器中打开目标网站</li></ul><h3 id="身份卡片-cookie-lab" tabindex="-1">身份卡片（Cookie Lab） <a class="header-anchor" href="#身份卡片-cookie-lab" aria-label="Permalink to &quot;身份卡片（Cookie Lab）&quot;">​</a></h3><p>有些网站需要登录后才能访问内容。身份卡片标签页允许你管理浏览器的 Cookie，在提取需要认证的页面时携带身份信息。</p><blockquote><p>TODO: 截图 - 身份卡片界面，展示 Cookie 注入和查看功能</p></blockquote><p><strong>使用场景</strong>：</p><ul><li>提取需要登录才能查看的页面内容</li><li>管理多个网站的认证信息</li><li>测试不同用户身份下的页面表现</li></ul><h3 id="api-嗅探" tabindex="-1">API 嗅探 <a class="header-anchor" href="#api-嗅探" aria-label="Permalink to &quot;API 嗅探&quot;">​</a></h3><p>当使用智能或交互模式加载页面时，API 嗅探器会自动拦截并记录页面发起的 <code>XMLHttpRequest</code> 和 <code>fetch</code> 请求。</p><blockquote><p>TODO: 截图 - API 嗅探界面，展示发现的 API 请求列表</p></blockquote><p><strong>发现的内容包括</strong>：</p><table tabindex="0"><thead><tr><th>信息</th><th>说明</th></tr></thead><tbody><tr><td>请求方法</td><td>GET / POST / PUT / DELETE 等</td></tr><tr><td>请求 URL</td><td>完整的 API 地址</td></tr><tr><td>内容类型</td><td>响应内容的 MIME 类型</td></tr><tr><td>时间戳</td><td>请求发生的时间</td></tr></tbody></table><p>这对于分析页面的数据来源、逆向接口调用非常有用。你可以复制 API URL 到 API 测试工具中进一步分析。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="自定义元数据提取规则" tabindex="-1">自定义元数据提取规则 <a class="header-anchor" href="#自定义元数据提取规则" aria-label="Permalink to &quot;自定义元数据提取规则&quot;">​</a></h3><p>对于某些特殊站点，默认的元数据提取（标题、作者、发布日期等）可能不够准确。站点配方支持三种元数据提取方式：</p><ul><li><strong>JSON-LD</strong>：从结构化数据中提取（<code>&lt;script type=&quot;application/ld+json&quot;&gt;</code>）</li><li><strong>脚本变量</strong>：从页面内嵌的 JavaScript 变量中提取（如 Bilibili 的 <code>__INITIAL_STATE__</code>）</li><li><strong>Meta 标签</strong>：从 HTML <code>&lt;meta&gt;</code> 标签中提取</li></ul><p>在配方编辑器中，你可以为每个站点自定义这些规则，支持多字段映射和值回退。</p><h3 id="纯净模式" tabindex="-1">纯净模式 <a class="header-anchor" href="#纯净模式" aria-label="Permalink to &quot;纯净模式&quot;">​</a></h3><p>在快速或智能提取时，可以开启 <strong>纯净模式</strong> 来过滤掉所有超链接，只保留纯文本内容。这在提取的链接过多影响阅读时特别有用——例如提取一个包含大量导航链接的页面。</p><h3 id="与-ai-聊天联动" tabindex="-1">与 AI 聊天联动 <a class="header-anchor" href="#与-ai-聊天联动" aria-label="Permalink to &quot;与 AI 聊天联动&quot;">​</a></h3><p>提取结果可以一键发送到 AI 聊天窗口，让你能基于网页内容继续与 AI 对话。在工作台的结果区点击 <strong>发送到聊天</strong> 按钮即可，系统会自动带上标题和来源 URL。</p><h3 id="利用内置配方批量提取" tabindex="-1">利用内置配方批量提取 <a class="header-anchor" href="#利用内置配方批量提取" aria-label="Permalink to &quot;利用内置配方批量提取&quot;">​</a></h3><p>内置配方涵盖了 Bilibili、GitHub 等高频站点。如果需要批量提取这些网站的内容，只需重复输入 URL 并选择快速模式即可——配方会自动匹配并应用于每个页面，无需重复配置提取规则。</p><h3 id="本地代理调试" tabindex="-1">本地代理调试 <a class="header-anchor" href="#本地代理调试" aria-label="Permalink to &quot;本地代理调试&quot;">​</a></h3><p>交互模式通过本地代理服务器加载目标页面（绕过同源策略限制）。这意味着你可以在工具中预览任意网页，即使该网页通过 <code>X-Frame-Options</code> 禁止了 iframe 嵌入。代理服务器会在工具关闭时自动释放。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-快速模式和智能模式有什么区别-我该用哪个" tabindex="-1">Q：快速模式和智能模式有什么区别？我该用哪个？ <a class="header-anchor" href="#q-快速模式和智能模式有什么区别-我该用哪个" aria-label="Permalink to &quot;Q：快速模式和智能模式有什么区别？我该用哪个？&quot;">​</a></h3><p><strong>快速模式</strong> 通过纯 HTTP 请求获取网页的 HTML，然后进行清洗。它<strong>极快</strong>（毫秒级），但不执行任何 JavaScript——对于用 JS 动态渲染内容的页面（如 Vue/React 构建的 SPA），它只能获取到初始 HTML 骨架。</p><p><strong>智能模式</strong> 会在隐藏的浏览器引擎中渲染目标页面，等待 JavaScript 执行完成后才提取内容。它<strong>较慢</strong>（通常 3-15 秒），但能完整获取动态内容。</p><p><strong>选择建议</strong>：</p><ul><li>大多数静态博客、新闻文章、文档 → <strong>快速模式</strong></li><li>Vue/React 单页应用、需要等待加载的页面、登录后内容 → <strong>智能模式</strong></li><li>需要精细控制提取规则并保存配方 → <strong>交互模式</strong></li></ul><h3 id="q-提取结果显示为空或者质量很低怎么办" tabindex="-1">Q：提取结果显示为空或者质量很低怎么办？ <a class="header-anchor" href="#q-提取结果显示为空或者质量很低怎么办" aria-label="Permalink to &quot;Q：提取结果显示为空或者质量很低怎么办？&quot;">​</a></h3><p>可能的原因和解决办法：</p><ol><li><strong>页面是动态加载的</strong>：试试切换到智能模式，让浏览器渲染完成后再提取</li><li><strong>页面需要等待特定元素</strong>：在智能模式下使用 <code>waitFor</code> 参数指定需要等待出现的 CSS 选择器</li><li><strong>目标页面有反爬机制</strong>：交互模式内置了反检测脚本，尝试先在交互模式中加载页面查看效果</li><li><strong>正文内容被噪音覆盖</strong>：在交互模式中使用排除规则（exclude）手动移除噪声元素</li><li><strong>可以创建配方</strong>：如果某个网站总是提取不好，考虑为该网站创建一个定制配方</li></ol><h3 id="q-保存的配方对其他页面生效吗" tabindex="-1">Q：保存的配方对其他页面生效吗？ <a class="header-anchor" href="#q-保存的配方对其他页面生效吗" aria-label="Permalink to &quot;Q：保存的配方对其他页面生效吗？&quot;">​</a></h3><p>这取决于你配置的匹配规则：</p><ul><li><strong>域名精确匹配</strong>：配方只对配置的域名生效（如 <code>www.example.com</code>）</li><li><strong>路径模式</strong>：使用 <code>glob</code> 通配符控制更精确的路径匹配（如 <code>/article/**</code> 只匹配文章路径）</li><li><strong>默认行为</strong>：如果只配置了域名，该域名下的所有页面都会尝试应用此配方</li></ul><p>一个站点可以配置多个配方，系统会按照&quot;域名+路径&quot;最精确的匹配规则优先选择。</p><h3 id="q-交互模式无法加载某些网站怎么办" tabindex="-1">Q：交互模式无法加载某些网站怎么办？ <a class="header-anchor" href="#q-交互模式无法加载某些网站怎么办" aria-label="Permalink to &quot;Q：交互模式无法加载某些网站怎么办？&quot;">​</a></h3><p>这通常由以下原因导致：</p><ol><li><strong>网站有严格的反爬机制</strong>：交互模式内置了反检测脚本（隐藏 WebView 特征、伪装 <code>navigator.webdriver</code> 等），但有些网站的反爬策略可能会识别出非真实浏览器环境</li><li><strong>需要登录的页面</strong>：先在身份卡片中注入对应网站的 Cookie 后再加载</li><li><strong>代理服务器地址被屏蔽</strong>：少数网站会屏蔽来自本地代理的请求，这种情况建议使用智能模式的后端代理</li><li><strong>跨域 CSP 限制</strong>：虽然有代理绕过了 iframe 禁止策略，但某些 CSP 规则仍可能影响资源加载</li></ol><p>遇到加载问题，可以先查看右侧的 <strong>API 嗅探</strong> 面板是否有请求被拦截，这通常能提供排查线索。</p><h3 id="q-如何清空-api-嗅探的记录" tabindex="-1">Q：如何清空 API 嗅探的记录？ <a class="header-anchor" href="#q-如何清空-api-嗅探的记录" aria-label="Permalink to &quot;Q：如何清空 API 嗅探的记录？&quot;">​</a></h3><p>在 <strong>API 嗅探</strong> 标签页中，点击顶部的清空按钮即可一键删除所有已发现的 API 请求记录。工具关闭或重新加载页面时，嗅探记录也会自动清除。</p><h3 id="q-内置配方可以修改吗" tabindex="-1">Q：内置配方可以修改吗？ <a class="header-anchor" href="#q-内置配方可以修改吗" aria-label="Permalink to &quot;Q：内置配方可以修改吗？&quot;">​</a></h3><p>内置配方（带有&quot;内置&quot;标签的）<strong>不可删除和修改</strong>，但你可以通过以下方式绕过：</p><ol><li><strong>禁用它</strong>：在配方管理页面点击禁用按钮，内置配方将不再自动匹配</li><li><strong>创建覆盖配方</strong>：创建一个同名域名但规则更精细的用户配方，系统会自动优先选用</li><li><strong>复制为自定义配方</strong>：在交互模式中手动加载目标页面，参考内置配方的规则重建一份并保存</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>内置配方会随工具更新而迭代优化，如果你对某个内置配方有改进建议，欢迎提交 Issue 或 PR。</p></div>',125)])])}const u=o(l,[["render",d]]);export{g as __pageData,u as default};
